class Solution {
    public boolean canPartitionKSubsets(int[] nums, int k) {
        int sum = 0;
        for (int num : nums) sum += num;
        if (sum % k != 0) return false;
        int target = sum / k;
        Arrays.sort(nums);
        if (nums[nums.length - 1] > target) return false;
        boolean[] used = new boolean[nums.length];
        return backtrack(nums, k, target, 0, used);
    }

    private boolean backtrack(int[] nums, int k, int target, int start, boolean[] used) {
        if (k == 0) return true;
        for (int i = start; i < nums.length; i++) {
            if (used[i] || nums[i] > target) continue;
            if (i > start && nums[i] == nums[i - 1] && !used[i - 1]) continue;
            used[i] = true;
            if (nums[i] == target || backtrack(nums, k - 1, target, 0, used)) return true;
            used[i] = false;
        }
        return false;
    }
}
